function json_response($payload, int $status = 200): void {
    http_response_code($status);
    header('Content-Type: application/json; charset=utf-8');
    header('Cache-Control: no-store');
    echo json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES | JSON_PRETTY_PRINT);
    exit;
}
function ok($data = null, array $extra = []): void { $p = ['ok' => true]; if ($data !== null) $p['data'] = $data; json_response(array_merge($p, $extra)); }
function fail(string $message, int $status = 400, array $extra = []): void { json_response(array_merge(['ok' => false, 'error' => $message], $extra), $status); }
function read_json_file(string $path, $default = []) { if (!is_file($path)) return $default; $raw = file_get_contents($path); if ($raw === false || trim($raw) === '') return $default; $d = json_decode($raw, true); return is_array($d) ? $d : $default; }
function write_json_file(string $path, $data): void { $dir = dirname($path); if (!is_dir($dir)) mkdir($dir, 0775, true); $tmp = $path . '.tmp'; file_put_contents($tmp, json_encode($data, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES | JSON_PRETTY_PRINT) . "\n", LOCK_EX); rename($tmp, $path); }
function append_jsonl(string $path, array $entry): void { $dir = dirname($path); if (!is_dir($dir)) mkdir($dir, 0775, true); file_put_contents($path, json_encode($entry, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) . "\n", FILE_APPEND | LOCK_EX); }
function body_json() { $raw = file_get_contents('php://input') ?: ''; if ($raw === '') return []; $d = json_decode($raw, true); if (!is_array($d)) fail('JSON غير صالح', 400); return $d; }
function now_iso(): string { return date('c'); }
function base_url(): string { $https = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off') || (($_SERVER['HTTP_X_FORWARDED_PROTO'] ?? '') === 'https'); return ($https ? 'https' : 'http') . '://' . ($_SERVER['HTTP_HOST'] ?? '127.0.0.1'); }
