function role_rank(?array $u): int { $r = $u['role'] ?? ROLE_GUEST; return [ROLE_GUEST=>0,ROLE_USER=>1,ROLE_ADMIN=>2,ROLE_OWNER=>3][$r] ?? 0; }
function require_role(?array $u, string $role): array { $need=[ROLE_USER=>1,ROLE_ADMIN=>2,ROLE_OWNER=>3][$role] ?? 0; if (role_rank($u) < $need) fail('ليست لديك الصلاحية المطلوبة', 403); return $u; }
function public_user(?array $u): ?array { if (!$u) return null; return ['email'=>$u['email']??'', 'name'=>$u['name']??'', 'picture'=>$u['picture']??'', 'role'=>$u['role']??ROLE_USER, 'created_at'=>$u['created_at']??null, 'last_login_at'=>$u['last_login_at']??null]; }
