function auth_path(string $f): string { return auth_dir() . '/' . $f; }
function load_auth_config(): array { $cfg=['google_client_id'=>'','google_client_secret'=>'','owner_email'=>OWNER_EMAIL,'redirect_uri'=>'','allow_dev_login'=>false]; foreach ([auth_path('config.json'), project_root().'/auth_config.json'] as $p) { $x=read_json_file($p, []); if (is_array($x)) $cfg=array_merge($cfg,$x); } foreach (['GOOGLE_CLIENT_ID'=>'google_client_id','GOOGLE_CLIENT_SECRET'=>'google_client_secret','GOOGLE_REDIRECT_URI'=>'redirect_uri'] as $env=>$key) if (getenv($env)) $cfg[$key]=getenv($env); return $cfg; }
function load_users(): array { $d=read_json_file(auth_path('users.json'), ['users'=>[]]); return $d['users'] ?? []; }
function save_users(array $users): void { write_json_file(auth_path('users.json'), ['users'=>$users,'updated_at'=>now_iso()]); }
function session_id_from_cookie(): ?string { return $_COOKIE[SESSION_COOKIE] ?? null; }
function load_sessions(): array { $d=read_json_file(auth_path('sessions.json'), ['sessions'=>[]]); return $d['sessions'] ?? []; }
function save_sessions(array $s): void { write_json_file(auth_path('sessions.json'), ['sessions'=>$s,'updated_at'=>now_iso()]); }
function current_user(): ?array { $sid=session_id_from_cookie(); if (!$sid) return null; $sessions=load_sessions(); $rec=$sessions[$sid] ?? null; if (!$rec) return null; if (($rec['expires_at'] ?? 0) < time()) return null; $users=load_users(); return public_user($users[$rec['email']] ?? null); }
function set_session(array $u): string { $sid=bin2hex(random_bytes(24)); $s=load_sessions(); $s[$sid]=['email'=>$u['email'],'created_at'=>time(),'expires_at'=>time()+14*86400]; save_sessions($s); setcookie(SESSION_COOKIE,$sid,['expires'=>time()+14*86400,'path'=>'/','httponly'=>true,'samesite'=>'Lax']); return $sid; }
function destroy_session(): void { $sid=session_id_from_cookie(); if ($sid) { $s=load_sessions(); unset($s[$sid]); save_sessions($s); } setcookie(SESSION_COOKIE,'',['expires'=>time()-3600,'path'=>'/','httponly'=>true,'samesite'=>'Lax']); }
function log_activity(?string $email, ?string $role, string $action, string $target='', array $detail=[]): void { append_jsonl(auth_path('activity.jsonl'), ['ts'=>now_iso(),'actor_email'=>$email,'actor_role'=>$role,'action'=>$action,'target'=>$target,'detail'=>$detail]); }
function upsert_user(string $email, string $name='', string $picture='', string $google_sub=''): array { $email=norm_email($email); if (!$email || !str_contains($email,'@')) fail('بريد غير صالح', 400); $users=load_users(); $u=$users[$email] ?? ['email'=>$email,'created_at'=>now_iso(),'role'=>($email===norm_email(OWNER_EMAIL)?ROLE_OWNER:ROLE_USER)]; $u['name']=$name ?: ($u['name'] ?? $email); $u['picture']=$picture ?: ($u['picture'] ?? ''); if ($google_sub) $u['google_sub']=$google_sub; $u['last_login_at']=now_iso(); if ($email===norm_email(OWNER_EMAIL)) $u['role']=ROLE_OWNER; $users[$email]=$u; save_users($users); return public_user($u); }
