function sort_taxa(array $taxa): array { usort($taxa, fn($a,$b)=>[strtolower($a['classification']['family']??''),strtolower($a['classification']['genus']??''),strtolower($a['scientific_name']??''),$a['id']??''] <=> [strtolower($b['classification']['family']??''),strtolower($b['classification']['genus']??''),strtolower($b['scientific_name']??''),$b['id']??'']); return $taxa; }
function stats(array $taxa): array { $byh=[];$byf=[];$native=0; foreach($taxa as $t){$h=$t['habit']??'?';$f=$t['classification']['family']??'?';$byh[$h]=($byh[$h]??0)+1;$byf[$f]=($byf[$f]??0)+1;if(!empty($t['native_to_iraq']))$native++;} arsort($byh); arsort($byf); return ['total'=>count($taxa),'native'=>$native,'non_native'=>count($taxa)-$native,'families'=>count($byf),'by_habit'=>$byh,'top_families'=>array_slice(array_map(fn($k,$v)=>[$k,$v],array_keys($byf),$byf),0,15)]; }
function flatten($v): string { if (is_array($v)) { $s=''; foreach($v as $x) $s.=' '.flatten($x); return $s; } return is_bool($v)?($v?'true':'false'):(string)$v; }
function bool_param($v): ?bool { if ($v===null || $v==='') return null; $s=mb_strtolower(trim((string)$v)); if (in_array($s,['true','1','yes','y','نعم'],true)) return true; if (in_array($s,['false','0','no','n','لا'],true)) return false; return null; }
function habit_in_category(?string $habit, string $cat): bool { $groups=category_groups(); $key=mb_strtolower(trim($cat)); if($key==='')return true; if(isset($groups[$key])) return in_array($habit,$groups[$key]['habits'],true); foreach($groups as $g){ if(mb_strtolower($g['file'])===$key || mb_strtolower($g['label_en'])===$key) return in_array($habit,$g['habits'],true); } foreach(habit_files() as $h=>$meta) if($h===$habit && mb_strtolower($meta['category_group'])===$key) return true; return false; }
function summarize(array $t): array { $cls=$t['classification']??[]; return ['id'=>$t['id']??'','scientific_name'=>$t['scientific_name']??'','family'=>$cls['family']??null,'genus'=>$cls['genus']??null,'habit'=>$t['habit']??null,'zones'=>$t['zones']??[],'native_to_iraq'=>$t['native_to_iraq']??null,'presence_in_iraq'=>$t['presence_in_iraq']??null,'iraq_local_status'=>$t['iraq_local_status']??null,'arabic_names'=>$t['names']['arabic']??[],'english_names'=>$t['names']['english']??[],'iucn'=>$t['iucn']??null,'flag'=>$t['flag']??null,'flagship_case'=>$t['flagship_case']??false]; }
function search_taxa(array $taxa, array $p): array { $q=trim((string)($p['q']??$p['query']??$p['text']??'')); $tokens=array_filter(preg_split('/\s+/u', mb_strtolower($q)) ?: []); $limit=max(0,(int)($p['limit']??200)); $offset=max(0,(int)($p['offset']??0)); $native=array_key_exists('native',$p)?bool_param($p['native']):(array_key_exists('native_to_iraq',$p)?bool_param($p['native_to_iraq']):null); $endemic=array_key_exists('endemic',$p)?bool_param($p['endemic']):(array_key_exists('endemic_to_iraq',$p)?bool_param($p['endemic_to_iraq']):null); $out=[]; foreach($taxa as $t){ $cls=$t['classification']??[]; if(($p['id']??'') && mb_stripos($t['id']??'', (string)$p['id'])===false) continue; foreach(['habit'=>'habit','family'=>'family','genus'=>'genus','order'=>'order'] as $pk=>$field){ if(($p[$pk]??'') && mb_strtolower((string)($field==='habit'?($t['habit']??''):($cls[$field]??''))) !== mb_strtolower((string)$p[$pk])) continue 2; } $zone=$p['zone']??$p['zones']??''; if($zone && !in_array($zone,$t['zones']??[],true)) continue; if($native!==null && (bool)($t['native_to_iraq']??false)!==$native) continue; if($endemic!==null && (bool)($t['endemic_to_iraq']??false)!==$endemic) continue; if(($p['presence']??$p['presence_in_iraq']??'') && ($t['presence_in_iraq']??'') !== ($p['presence']??$p['presence_in_iraq'])) continue; if(($p['local_status']??$p['iraq_local_status']??'') && ($t['iraq_local_status']??'') !== ($p['local_status']??$p['iraq_local_status'])) continue; if(($p['iucn']??$p['iucn_category']??'') && (($t['iucn']['category']??null) !== ($p['iucn']??$p['iucn_category']))) continue; if(($p['category']??$p['category_group']??'') && !habit_in_category($t['habit']??null, (string)($p['category']??$p['category_group']))) continue; if($tokens){ $blob=mb_strtolower(flatten($t)); foreach($tokens as $tok) if(mb_strpos($blob,$tok)===false) continue 2; } $out[]=$t; } $sort=$p['sort_by']??'family'; usort($out,function($a,$b)use($sort){$ka=$sort==='id'?($a['id']??''):($sort==='scientific_name'?($a['scientific_name']??''):($sort==='habit'?($a['habit']??''):($a['classification']['family']??'')));$kb=$sort==='id'?($b['id']??''):($sort==='scientific_name'?($b['scientific_name']??''):($sort==='habit'?($b['habit']??''):($b['classification']['family']??'')));return mb_strtolower($ka)<=>mb_strtolower($kb);}); if(bool_param($p['sort_desc']??null)) $out=array_reverse($out); $total=count($out); return ['total'=>$total,'count'=>count(array_slice($out,$offset,$limit ?: $total)),'offset'=>$offset,'limit'=>$limit,'results'=>array_slice($out,$offset,$limit ?: $total)]; }
function norm_names($items, string $def='متوسطة'): array { $out=[]; foreach(($items??[]) as $it){ if(is_string($it)){$name=trim($it);$conf=$def;} elseif(is_array($it)){$name=trim((string)($it['name']??''));$conf=in_array($it['confidence']??$def,allowed_confidence(),true)?$it['confidence']:$def;} else continue; if($name!=='') $out[]=['name'=>$name,'confidence'=>$conf]; } return $out; }
function norm_english($items): array { $out=[]; foreach(($items??[]) as $it){$s=is_array($it)?trim((string)($it['name']??'')):trim((string)$it); if($s!=='')$out[$s]=$s;} return array_values($out); }
function normalize_taxon(array $raw): array { $err=[]; $id=strtoupper(str_replace('_','-',trim((string)($raw['id']??'')))); if(!$id||!preg_match('/^[A-Z]{3}-[A-Z]{3}-[A-Z0-9]{2,4}$/',$id))$err[]='صيغة id غير صالحة'; $sci=preg_replace('/\s+/u',' ',trim((string)($raw['scientific_name']??''))); if(!$sci)$err[]='scientific_name مطلوب'; $cls=is_array($raw['classification']??null)?$raw['classification']:[]; foreach(['order','family','genus'] as $k) if(trim((string)($cls[$k]??''))==='') $err[]="classification.$k مطلوب"; $names=is_array($raw['names']??null)?$raw['names']:[]; $arab=norm_names($names['arabic']??[]); if(!$arab)$err[]='names.arabic مطلوب'; $habit=$raw['habit']??null; if(!array_key_exists((string)$habit,habit_files()))$err[]='habit غير صالح'; $zones=$raw['zones']??[]; if(is_string($zones))$zones=[$zones]; $zones=array_values(array_unique(array_filter(array_map('trim',$zones)))); foreach($zones as $z) if(!in_array($z,allowed_zones(),true))$err[]='zones غير معروفة'; $pres=$raw['presence_in_iraq']??''; if(!in_array($pres,allowed_presence(),true))$err[]='presence_in_iraq غير صالح'; $local=$raw['iraq_local_status']??''; if(!in_array($local,allowed_local_status(),true))$err[]='iraq_local_status غير صالح'; $iucn=is_array($raw['iucn']??null)?$raw['iucn']:[]; $cat=$iucn['category']??null; if($cat==='مُقيَّم'){$iucn['assessment_noted']=true;$cat=null;} if($cat===''||$cat==='null'||$cat==='None')$cat=null; if($cat!==null && !in_array($cat,iucn_codes(),true))$cat=null; $native=(bool)($raw['native_to_iraq']??false); if(!$native && trim((string)($raw['introduction_status']??''))==='')$err[]='introduction_status مطلوب للأنواع غير الأصلية'; if($err) fail(implode('؛ ',$err),422); $out=['id'=>$id,'scientific_name'=>$sci]; if(trim((string)($raw['taxonomic_note']??''))!=='')$out['taxonomic_note']=trim((string)$raw['taxonomic_note']); $out['classification']=['order'=>trim((string)$cls['order']),'family'=>trim((string)$cls['family']),'genus'=>trim((string)$cls['genus'])]; foreach(['division','class','subgenus','section'] as $k) if(!empty($cls[$k]))$out['classification'][$k]=trim((string)$cls[$k]); $out['names']=['arabic'=>$arab,'english'=>norm_english($names['english']??[])]; $kur=norm_names($names['kurdish']??[]); if($kur)$out['names']['kurdish']=$kur; $out['habit']=$habit; $out['zones']=$zones; $out['native_to_iraq']=$native; if(array_key_exists('endemic_to_iraq',$raw))$out['endemic_to_iraq']=(bool)$raw['endemic_to_iraq']; $out['presence_in_iraq']=$pres; if(!$native)$out['introduction_status']=trim((string)$raw['introduction_status']); $out['iucn']=['category'=>$cat,'verified_in_session'=>$cat!==null && !empty($iucn['verified_in_session'])]; if(!empty($iucn['assessment_noted']))$out['iucn']['assessment_noted']=true; if(!empty($iucn['note']))$out['iucn']['note']=trim((string)$iucn['note']); $out['iraq_local_status']=$local; foreach(['flag','notes'] as $k)$out[$k]=trim((string)($raw[$k]??'')); if(array_key_exists('flagship_case',$raw))$out['flagship_case']=(bool)$raw['flagship_case']; return array_filter($out, fn($v)=>$v!=='' && $v!==null); }
function deep_merge($a,$b){ foreach($b as $k=>$v){ if(is_array($v)&&isset($a[$k])&&is_array($a[$k])&&array_keys($v)!==range(0,count($v)-1))$a[$k]=deep_merge($a[$k],$v); else $a[$k]=$v; } return $a; }
function find_taxon(array $taxa, string $id): ?array { $id=strtoupper(trim($id)); foreach($taxa as $t) if(($t['id']??'')===$id) return $t; return null; }
function assert_unique(array $taxa, array $taxon, ?string $skip=null): void { foreach($taxa as $t){ if($skip && ($t['id']??'')===$skip) continue; if(($t['id']??'')===$taxon['id']) fail('معرّف مكرر: '.$taxon['id'],422); if(mb_strtolower($t['scientific_name']??'')===mb_strtolower($taxon['scientific_name'])) fail('اسم علمي مكرر: '.$taxon['scientific_name'],422); } }
function file_meta(string $ar,string $en,string $subset,int $count,string $parent,array $extra=[]): array { return array_merge(['project'=>'Iraqi Flora Encyclopedia / موسوعة الفلورا العراقية','phase'=>'php-managed-dataset','title_ar'=>$ar,'title_en'=>$en,'subset'=>$subset,'taxa_count'=>$count,'parent_dataset'=>$parent,'updated_on'=>date('Y-m-d'),'language_convention'=>'التنوين يُرسم على الحرف الأخير دائماً (حقاً لا حقًا)','schema_ref'=>'schema/plant_taxon.schema.json'],$extra); }
